export function createCartState() {
  return { items: [], total: 0 }
}

export function addItem(state, item) {
  const next = state
  next.items.push(item)
  next.total = state.items.length
  return next
}

import { addItem } from './useCartState.mjs'

export function CartPanel({ state, item }) {
  const next = addItem(state, item)
  return String(next.total)
}

import test from 'node:test'
import assert from 'node:assert/strict'
import { addItem, createCartState } from './src/useCartState.mjs'

test('addItem returns a new state object without mutating previous state', () => {
  const state = createCartState()
  const next = addItem(state, { id: 'a', label: 'Alpha' })
  assert.notEqual(next, state)
  assert.deepEqual(state.items, [])
  assert.equal(state.total, 0)
  assert.deepEqual(next.items, [{ id: 'a', label: 'Alpha' }])
  assert.equal(next.total, 1)
})

content.thinking:
Now I understand the bug. The `addItem` function is mutating the existing state object by pushing directly to `state.items`. In React, when using state, you must create a new object rather than mutating the existing one.

The bug is in `addItem`:
```javascript
export function addItem(state, item) {
  const next = state  // This just references the same object
  next.items.push(item)  // Mutates the original state
  next.total = state.items.length
  return next
}
```

The fix should create a new object with a new items array:
```javascript
export function addItem(state, item) {
  return {
    ...state,
    items: [...state.items, item],  // New array with new item
    total: state.items.length + 1   // Increment total
  }
}
```

Or alternatively:
```javascript
export function addItem(state, item) {
  const nextItems = [...state.items, item]
  return {
    ...state,
    items: nextItems,
    total: nextItems.length
  }
}
```

